#!/usr/bin/env python3
"""Tests for GCodeZAA processing with and without slicer headers."""

import sys

sys.path.insert(0, "GCodeZAA")

from gcodezaa.process import process_gcode
from gcodezaa.process import _detect_line_type_from_line
from gcodezaa.process import _prime_context_state_for_line
from gcodezaa.context import ProcessorContext
from gcodezaa.slicer_syntax import Slicer, SlicerSyntax


def test_process_gcode_with_header_succeeds():
    gcode_with_header = [
        "; Generated by BambuStudio\n",
        "; Sliced by OrcaSlicer\n",
        "G28\n",
        "G92 X0 Y0 Z0 E0\n",
        "; EXECUTABLE_BLOCK_START\n",
        "G1 X10 Y0 Z0.2 F3000\n",
        "G1 X20 Y0 Z0.2 F3000\n",
        "; EXECUTABLE_BLOCK_END\n",
    ]

    result = process_gcode(gcode_with_header, ".")
    assert len(result) == len(gcode_with_header)


def test_process_gcode_without_header_succeeds():
    gcode_without_header = [
        "G28\n",
        "G92 X0 Y0 Z0 E0\n",
        "; EXECUTABLE_BLOCK_START\n",
        "G1 X10 Y0 Z0.2 F3000\n",
        "G1 X20 Y0 Z0.2 F3000\n",
        "; EXECUTABLE_BLOCK_END\n",
    ]

    result = process_gcode(gcode_without_header, ".")
    assert len(result) == len(gcode_without_header)


def test_process_gcode_with_arcs_and_no_header_preserves_arcs():
    gcode_with_arcs = [
        "G28\n",
        "G92 X0 Y0 Z0 E0\n",
        "; EXECUTABLE_BLOCK_START\n",
        "G1 X10 Y0 Z0.2 F3000\n",
        "G2 X20 Y10 I5 J0 E5 F1200\n",
        "G3 X30 Y10 I5 J0 E5 F1200\n",
        "; EXECUTABLE_BLOCK_END\n",
    ]

    result = process_gcode(gcode_with_arcs, ".")
    arc_count = sum(1 for line in result if "G2 " in line or "G3 " in line)
    assert arc_count >= 2


def test_process_gcode_without_executable_markers_succeeds():
    gcode_without_markers = [
        "; Generated by OrcaSlicer\n",
        "G28\n",
        "G92 X0 Y0 Z0 E0\n",
        "G1 X10 Y0 Z0.2 F3000\n",
        "G1 X20 Y0 Z0.2 F3000\n",
    ]

    result = process_gcode(gcode_without_markers, ".")

    assert len(result) == len(gcode_without_markers)
    assert result[0] == gcode_without_markers[0]


def test_detect_line_type_from_line_handles_feature_and_inline_ironing_comments():
    syntax = SlicerSyntax(Slicer.BAMBU)

    assert _detect_line_type_from_line("; FEATURE: Ironing\n", syntax) == "ironing"
    assert _detect_line_type_from_line("G1 X72.658 Y130.688 E.00078 ; ironing\n", syntax) == "ironing"
    assert _detect_line_type_from_line(
        "G1 X67.37 Y125.569 E.00681 ; infill | Old Flow Value: 0.01161 Length: 0.35570\n",
        syntax,
    ) == "infill"


def test_detect_line_type_from_line_handles_type_marker_for_orca():
    syntax = SlicerSyntax(Slicer.ORCA)

    assert _detect_line_type_from_line(";TYPE:Ironing\n", syntax) == "ironing"


def test_prime_context_state_g92_persists_into_first_window_move():
    gcode = [
        "; EXECUTABLE_BLOCK_START\n",
        "G1 X101.0 Y200.0 Z0.2 E0.1 F1200\n",
    ]
    ctx = ProcessorContext(gcode, ".")

    _prime_context_state_for_line(ctx, "G90\n")
    _prime_context_state_for_line(ctx, "G92 X100.0 Y200.0 Z0.2 E0\n")
    _prime_context_state_for_line(ctx, gcode[1])

    assert ctx.relative_positioning is False
    assert abs(ctx.last_p[0] - 101.0) < 1e-9
    assert abs(ctx.last_p[1] - 200.0) < 1e-9
    assert abs(ctx.last_p[2] - 0.2) < 1e-9


def test_prime_context_state_relative_arc_accumulates_position():
    ctx = ProcessorContext(["G2 X5.0 Y-2.0 E0.1\n"], ".")
    ctx.last_p = (10.0, 10.0, 0.2)

    _prime_context_state_for_line(ctx, "G91\n")
    _prime_context_state_for_line(ctx, "G2 X5.0 Y-2.0 E0.1\n")

    assert ctx.relative_positioning is True
    assert abs(ctx.last_p[0] - 15.0) < 1e-9
    assert abs(ctx.last_p[1] - 8.0) < 1e-9
    assert abs(ctx.last_p[2] - 0.2) < 1e-9


def test_prime_context_state_absolute_arc_sets_position():
    ctx = ProcessorContext(["G2 X5.0 Y6.0 E0.1\n"], ".")
    ctx.last_p = (10.0, 10.0, 0.2)

    _prime_context_state_for_line(ctx, "G90\n")
    _prime_context_state_for_line(ctx, "G2 X5.0 Y6.0 E0.1\n")

    assert ctx.relative_positioning is False
    assert abs(ctx.last_p[0] - 5.0) < 1e-9
    assert abs(ctx.last_p[1] - 6.0) < 1e-9
    assert abs(ctx.last_p[2] - 0.2) < 1e-9
